// Typed asset module for the Aura3D project.
//
// Normally generated by `npx @aura3d/cli assets add ./sneaker.glb --name sneaker`.
// We author it directly here with the public `defineAuraAssets` helper so the
// only asset path in the app is the provided, real file. No invented paths.
//
// The provided model lives at `public/benchmark/assets/sneaker.glb`, which Vite
// serves from the web root at `/benchmark/assets/sneaker.glb`.
import { defineAuraAssets } from "@aura3d/engine";

export const assets = defineAuraAssets({
  sneaker: {
    type: "model",
    format: "glb",
    url: "/benchmark/assets/sneaker.glb",
    sizeBytes: 7833592,
    metadata: {
      license: "provided-by-benchmark",
    },
  },
});

export type AuraAssets = typeof assets;
